function() {
  var activeGroups = {{Data Layer | CookiePro Active Groups}}; // Reference your Data Layer Variable
  var consentStatus = [];

  if (activeGroups && activeGroups.includes('C0001')) {
    consentStatus.push('Strictly Necessary');
  }
  if (activeGroups && activeGroups.includes('C0002')) {
    consentStatus.push('Analytics');
  }
  if (activeGroups && activeGroups.includes('C0003')) {
    consentStatus.push('Performance/Functional');
  }
  if (activeGroups && activeGroups.includes('C0004')) {
    consentStatus.push('Targeting/Adv');
  }

  // If no groups are active beyond C0001, or if it's explicitly denied everything non-necessary
  if (consentStatus.length === 1 && consentStatus[0] === 'Strictly Necessary') {
      return 'Only Strictly Necessary';
  } else if (consentStatus.length === 0) {
      return 'No Consent (All Denied)'; // Highly unlikely with C0001, but for completeness
  } else {
      return consentStatus.join(', '); // Join active categories
  }
}

function() {
  function generateRandom(min, max) {
    min = Math.ceil(min);
    max = Math.floor(max);
    return Math.floor(Math.random() * (max - min + 1)) + min;
  }

  function getRdtBrowserId() {
    if (!window._rdt_gtm_browserId) {
      window._rdt_gtm_browserId = new Date().getTime() + '' + generateRandom(100000, 999999);
    }
    return window._rdt_gtm_browserId;
  }

  function getRdtPageLoadId() {
    if (!window._rdt_gtm_pageLoadId) {
      window._rdt_gtm_pageLoadId = new Date().getTime() + '' + generateRandom(100000, 999999);
    }
    return window._rdt_gtm_pageLoadId;
  }

  var gtmData = window.google_tag_manager[{{Container ID}}].dataLayer.get('gtm');

  return gtmData.uniqueEventId + '_' + getRdtBrowserId() + '_' + getRdtPageLoadId();
}

function() {
  var currency = window.google_tag_manager[{{Container ID}}].dataLayer.get('ecommerce.currency') ||
                 window.google_tag_manager[{{Container ID}}].dataLayer.get('eventModel.currency') ||
                 window.google_tag_manager[{{Container ID}}].dataLayer.get('currency');
  return currency;
}

function() {
  var ecommerceItems = window.google_tag_manager[{{Container ID}}].dataLayer.get('ecommerce.items') || window.google_tag_manager[{{Container ID}}].dataLayer.get('eventModel.items');
  return JSON.stringify(ecommerceItems);
}

function() {
  var itemCount = window.google_tag_manager[{{Container ID}}].dataLayer.get('ecommerce.item_count') || window.google_tag_manager[{{Container ID}}].dataLayer.get('eventModel.itemCount') || window.google_tag_manager[{{Container ID}}].dataLayer.get('itemCount');
  return itemCount;
}

function() {
  var productData = window.google_tag_manager[{{Container ID}}].dataLayer.get('productsRows') || 
                    window.google_tag_manager[{{Container ID}}].dataLayer.get('eventModel.productsRows') ||
                    window.google_tag_manager[{{Container ID}}].dataLayer.get('productsJSON') ||
                    window.google_tag_manager[{{Container ID}}].dataLayer.get('eventModel.productsJSON');
  return productData;
}

function() {
  var userData = window.google_tag_manager[{{Container ID}}].dataLayer.get('user_data') || 
                 window.google_tag_manager[{{Container ID}}].dataLayer.get('eventModel.user_data');
  return userData;
}

function() {
  var value = window.google_tag_manager[{{Container ID}}].dataLayer.get('ecommerce.value') ||
                 window.google_tag_manager[{{Container ID}}].dataLayer.get('eventModel.value') ||
                 window.google_tag_manager[{{Container ID}}].dataLayer.get('transactionValue') ||
                 window.google_tag_manager[{{Container ID}}].dataLayer.get('eventModel.transactionValue');

  return value; 
}

