var getRdt = function() {
  var _rdt = copyFromWindow('rdt');
  if (_rdt) {
    return _rdt;
  }

  var queue;
  setInWindow('rdt', function () {
    var sendEvent = copyFromWindow('rdt.sendEvent');
    if (sendEvent) {
      callInWindow('rdt.sendEvent.apply', _rdt, arguments);
    } else {
      queue(arguments);
    }
  });
  queue = createQueue('rdt.callQueue');
  return copyFromWindow('rdt');
};

