    }
  }
}

if (!eventMetadata.phoneNumber) {
  const phoneFromEventModel = eventModel && eventModel.user_data && (eventModel.user_data.phone_number || eventModel.user_data.sha256_phone_number);

  if (phoneFromEventModel) {
