- name: Test Zero Value Handling
  code: |
    mockData = {
      id: "t2_reddit",
      eventType: "Purchase",
      transactionValue: 0, // Explicitly set to zero in UI
      currency: "USD",
    };

    // Set up non-zero values in data layer and ecommerce
